const CompressionFormat = @import("compression_format.zig").CompressionFormat;
const OutputFormat = @import("output_format.zig").OutputFormat;
const OutputFormatOptions = @import("output_format_options.zig").OutputFormatOptions;
const S3Location = @import("s3_location.zig").S3Location;

/// Represents options that specify how and where in Amazon S3 DataBrew writes
/// the output generated by
/// recipe jobs or profile jobs.
pub const Output = struct {
    /// The compression algorithm used to compress the output text of the job.
    compression_format: ?CompressionFormat,

    /// The data format of the output of the job.
    format: ?OutputFormat,

    /// Represents options that define how DataBrew formats job output files.
    format_options: ?OutputFormatOptions,

    /// The location in Amazon S3 where the job writes its output.
    location: S3Location,

    /// Maximum number of files to be generated by the job and written to the output
    /// folder. For output partitioned
    /// by column(s), the MaxOutputFiles value is the maximum number of files per
    /// partition.
    max_output_files: ?i32,

    /// A value that, if true, means that any data in the location specified for
    /// output is
    /// overwritten with new output.
    overwrite: bool = false,

    /// The names of one or more partition columns for the output of the job.
    partition_columns: ?[]const []const u8,

    pub const json_field_names = .{
        .compression_format = "CompressionFormat",
        .format = "Format",
        .format_options = "FormatOptions",
        .location = "Location",
        .max_output_files = "MaxOutputFiles",
        .overwrite = "Overwrite",
        .partition_columns = "PartitionColumns",
    };
};
